+package middleware
+
+import (
+	"net/http"
+	"strings"
+
+	"github.com/go-chi/chi/v5"
+)
+
+// standardHTTPMethods is the set of methods probed, in a stable order,
+// when building the Allow header for a 405 response.
+var standardHTTPMethods = []string{
+	http.MethodConnect,
+	http.MethodDelete,
+	http.MethodGet,
+	http.MethodHead,
+	http.MethodOptions,
+	http.MethodPatch,
+	http.MethodPost,
+	http.MethodPut,
+	http.MethodTrace,
+}
+
+// SetAllowHeader adds the Allow header for 405 responses based on
+// registered methods for the requested path, per RFC 9110. It has no
+// effect on requests that don't result in a 405, and never inspects the
+// response status code, so it stays cheap on the happy path.
+func SetAllowHeader(next http.Handler) http.Handler {
+	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
+		rctx := chi.RouteContext(r.Context())
+		if rctx == nil || rctx.Routes == nil {
+			next.ServeHTTP(w, r)
+			return
+		}
+
+		routePath := rctx.RoutePath
+		if routePath == "" {
+			if r.URL.RawPath != "" {
+				routePath = r.URL.RawPath
+			} else {
+				routePath = r.URL.Path
+			}
+			if routePath == "" {
+				routePath = "/"
+			}
+		}
+
+		tctx := chi.NewRouteContext()
+		if !rctx.Routes.Match(tctx, r.Method, routePath) {
+			var allowed []string
+			for _, method := range standardHTTPMethods {
+				mctx := chi.NewRouteContext()
+				if rctx.Routes.Match(mctx, method, routePath) {
+					allowed = append(allowed, method)
+				}
+			}
+			if len(allowed) > 0 {
+				w.Header().Set("Allow", strings.Join(allowed, ", "))
+			}
+		}
+
+		next.ServeHTTP(w, r)
+	})
+}
